E = dir(30 + 4*360/5);
O = (0,0);

draw((-1.2,0)--(1.2,0));
draw((0,-1.2)--(0,1.2));
draw(Circle(O,1));
draw(O--A);
draw(O--B);
draw(O--C);
draw(O--D);
draw(O--E);

label("$30^\circ$", A, A);
label("$102^\circ$", B, B);
label("$174^\circ$", C, C);
label("$246^\circ$", D, D);
label("$318^\circ$", E, E);
[/asy]

